function interpolate(s: string, params?: Params): string {
  if (!params) return s;
  return s.replace(/\{(\w+)\}/g, (_, k) => (k in params ? String(params[k]) : `{${k}}`));
}

export function translate(lang: Lang, key: string, params?: Params): string {
  const s = dict[lang][key] ?? dict.en[key] ?? key;
  return interpolate(s, params);
}

export function detectLang(): Lang {
  try {
    const stored = typeof localStorage !== 'undefined' ? localStorage.getItem('catan.lang') : null;
    if (stored === 'en' || stored === 'ko') return stored;
    if (typeof navigator !== 'undefined' && navigator.language?.toLowerCase().startsWith('ko')) return 'ko';
  } catch { /* SSR / sandboxed: fall through */ }
  return 'en';
}

export type TFn = (key: string, params?: Params) => string;
interface I18n { lang: Lang; setLang: (l: Lang) => void; t: TFn; }

// Default context works WITHOUT a provider (English) so server-rendered tests
// and any unwrapped render still produce valid output.
const I18nContext = createContext<I18n>({
  lang: 'en',
  setLang: () => {},
  t: (k, p) => translate('en', k, p),
});

export function LangProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<Lang>(detectLang);
  const setLang = (l: Lang) => {
    setLangState(l);
    try { if (typeof localStorage !== 'undefined') localStorage.setItem('catan.lang', l); } catch { /* ignore */ }
  };
  const t: TFn = (key, params) => translate(lang, key, params);
  return createElement(I18nContext.Provider, { value: { lang, setLang, t } }, children);
}

export function useI18n(): I18n {
  return useContext(I18nContext);
}

// Translate a resource name and an engine-assigned player name (You / AI N).
export const tRes = (t: TFn, r: Resource): string => t('res.' + r);
export function displayName(t: TFn, name: string): string {
  if (name === 'You') return t('player.you');
  const m = name.match(/^AI (\d+)$/);
  return m ? t('player.ai', { n: m[1]! }) : name;
}
